WorkflowProcessEvent.eventDescription:
function afterTaskComplete(colleagueId,nextSequenceId,userList){

// usuario = 33,16
// gerente = 43
// agente = 48

         
    var num_processo = getValue ("WKNumProces");     
    var usuario = getValue ("WKUser");   
    var problema = hAPI.getCardValue("DescrProblema");  
    var resolucao = hAPI.getCardValue("resolucaoTI");
    var esclarecimento = hAPI.getCardValue("ObsEsclarecTI");
    var obsgerente = hAPI.getCardValue("obsgerente");

    var EsclarecSolicit = hAPI.getCardValue("EsclarecSolicit");
    var ObsUsuario = hAPI.getCardValue("ObsUsuario");
   
    var agente = hAPI.getCardValue("matAgente");
    var gerente = hAPI.getCardValue("matSupervisor");
        

    if(nextSequenceId==33 && colleagueId == usuario){     

        // if (problema !== "" && problema !== null && colleagueId == usuario)
        if (problema !== null){     
            hAPI.setTaskComments(usuario, num_processo, 0, problema); 
        } 
        
    } 

    if(nextSequenceId==48 && colleagueId == agente){

        if (resolucao !== "") {
        hAPI.setTaskComments(agente, num_processo, 0, resolucao); 
    }

        if (esclarecimento !== "") {
        hAPI.setTaskComments(agente, num_processo, 0, esclarecimento); 
    }

}

    if(nextSequenceId==43 && colleagueId == gerente){

        if (obsgerente !== "") {
        hAPI.setTaskComments(gerente, num_processo, 0, obsgerente); 
}

}

    if(nextSequenceId==27 && colleagueId == usuario){

        if (ObsUsuario !== "") {
        hAPI.setTaskComments(usuario, num_processo, 0, ObsUsuario); 
    }

        if (EsclarecSolicit !== "") {
        hAPI.setTaskComments(usuario, num_processo, 0, EsclarecSolicit); 
    }

}

    }

function beforeSendData(customField, customFact) {

    customField[0] = hAPI.getCardValue("ComboProblema");

    customField[1] = hAPI.getCardValue("ComboUrgencia");

    customField[2] = hAPI.getCardValue("RdProblResolv");

    var field0 = hAPI.getCardValue('AvaliacaoAtend');
    field0 = +field0;
    if (!isNaN(field0)) {
        customFact[0] = field0;
    }
}

function afterTaskCreate(colleagueId){
  
    var nrProxAtividade = getValue("WKNextState");
    var threadDaSolicitacao = 0; // Normalmente 0, quando não for atividade paralela

    if (nrProxAtividade == "7"){
  
        var data = new Date();
        var numEmpresa = getValue("WKCompany");
        var colleagueId = hAPI.getCardValue("matAgente")

        var dia = hAPI.getCardValue("dia")
        var mes = hAPI.getCardValue("mes")
        var ano = hAPI.getCardValue("ano")
        var prazodia = hAPI.getCardValue("prazodia")
      
        //seta o dia, mês (Janeiro é 0) e ano
        data.setDate(dia);
        data.setMonth(mes-1);
        data.setFullYear(ano);
         
        // Recupera o numero da solicitação
        var numProcesso = getValue("WKNumProces");
      
        // Seta o prazo para as 14:00
        hAPI.setDueDate(numProcesso, threadDaSolicitacao, colleagueId, data, prazodia);
    }

}
